for p in range(1, 8):
    elements = PERIODS[p]
    lines.append(f'// ── {period_names[p]} ────────────────────────────────────────────')
    for z in elements:
        d = DATA[z]
        name = NAMES[z]
        lines.append(f'P7_STRATEGY[{z}] = {{  // {name}')

