        lines.append(f'  criticality: {{ usgsList: \'{cr["usgsList"]}\', euList: \'{cr["euList"]}\', chinaList: \'{cr["chinaList"]}\', overallRating: \'{cr["overallRating"]}\', note: \'{cr["note"]}\' }},')

