        lines.append(f'  substitutability: {{ substitutes: {subs_str}, substitutionCost: \'{sub["substitutionCost"]}\', performanceTradeoff: \'{sub["performanceTradeoff"]}\', substitutionFeasibility: \'{sub["substitutionFeasibility"]}\', note: \'{sub["note"]}\' }},')

